module top_module(
  input clk,
  input reset,
  output reg [3:0] count,
  output reg mod3
);reg [1:0] cnt_err;

  always @(posedge clk) begin
    if (reset) begin
      count <= 4'b0000;
      cnt_err <= 2'b00;
      mod3 <= 1'b0;
    end
    else begin
      count <= count + 1;
      cnt_err <= cnt_err + 1;
      if (cnt_err == 2'b10) begin
        cnt_err <= 2'b00;
        mod3 <= ~mod3;
      end
    end
  end

endmodule
